ALGORITHM AgglomerativeHierarchicalClustering
INPUT: dataset, distance metric, linkage method
OUTPUT: dendrogram

BEGIN
 // Initialize each data point as its own cluster
 clusters = dataset

 // Compute initial distance matrix
 distanceMatrix = computeDistanceMatrix(clusters, distance metric)

 // Merge closest clusters until only one cluster remains
 WHILE size(clusters) > 1 DO
 // Find the two closest clusters
 closestClusters = findClosestClusters(distanceMatrix)

 // Merge the closest clusters
 newCluster = mergeClusters(closestClusters)

 // Update the distance matrix
 distanceMatrix = updateDistanceMatrix(distanceMatrix, newCluster, linkage method)

 // Remove the merged clusters from the list of clusters
 clusters = removeMergedClusters(clusters, closestClusters)

 // Add the new cluster to the list of clusters
 clusters = addNewCluster(clusters, newCluster)
 END WHILE

 // Construct the dendrogram
 dendrogram = constructDendrogram(clusters)

 RETURN dendrogram
END

#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Define the structure for a cluster
typedef struct {
 int id;
 double x;
 double y;
} Cluster;

// Define the function to compute the distance between two clusters
double distance(Cluster c1, Cluster c2) {
 return sqrt(pow(c1.x - c2.x, 2) + pow(c1.y - c2.y, 2));
}

// Define the function to merge two clusters
Cluster merge(Cluster c1, Cluster c2) {
 Cluster newCluster;
 newCluster.id = c1.id;
 newCluster.x = (c1.x + c2.x) / 2;
 newCluster.y = (c1.y + c2.y) / 2;
 return newCluster;
}

int main() {
 // Define the dataset
 Cluster clusters[] = {{1, 1, 2}, {2, 3, 4}, {3, 5, 6}, {4, 7, 8}};
 int n = sizeof(clusters) / sizeof(clusters[0]);

 // Initialize the distance matrix
 double D[n][n];
 for (int i = 0; i < n; i++) {
 for (int j = 0; j < n; j++) {
 D[i][j] = distance(clusters[i], clusters[j]);
 }
 }

 // Merge closest clusters until only one cluster remains
 while (n > 1) {
 // Find the two closest clusters
 int minI = 0;
 int minJ = 1;
 double minD = D[0][1];
 for (int i = 0; i < n; i++) {
 for (int j = i + 1; j < n; j++) {
 if (D[i][j] < minD) {
 minI = i;
 minJ = j;
 minD = D[i][j];
 }
 }
 }

 // Merge the closest clusters
 Cluster newCluster = merge(clusters[minI], clusters[minJ]);

 // Update the distance matrix
 for (int i = 0; i < n; i++) {
 D[i][minI] = distance(clusters[i], newCluster);
 D[minI][i] = D[i][minI];
 }

 // Remove the merged clusters from the list of clusters
 for (int i = minJ; i < n - 1; i++) {
 clusters[i] = clusters[i + 1];
 }
 n--;
 }

 return 0;
}
